import { describe, it, expect } from "vitest";
import { processScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  describe("Quote - main items", () => {
    it.todo("should quote a single sword for a new customer");
    it.todo("should quote a single amulet for a new customer");
    it.todo("should quote a single staff for a new customer");
    it.todo("should quote a single potion for a new customer");
    it.todo("should sum base premiums for multiple main items");
  });

  describe("Quote - components", () => {
    it.todo("should charge 25G base premium for a single component");
    it.todo("should charge 60G for a building block of 3 alike components");
    it.todo("should charge per-component for non-block remainders");
  });

  describe("Quote - surcharges and discounts", () => {
    it.todo("should add 50% surcharge for cursed items");
    it.todo("should add 30% surcharge for items with enchantment >= 5");
    it.todo("should apply 20% loyalty discount for customers with >= 2 years");
    it.todo("should add 10% initial assessment surcharge on first insurance");
    it.todo("should apply 15% discount on each contract after the first");
    it.todo("should add 5G processing fee to every premium");
    it.todo("should round premium up in MHPCO's favor");
  });

  describe("Claim", () => {
    it.todo("should subtract 100G deductible from damage amount");
    it.todo("should cap total payout at 2x the insurance sum of the policy");
    it.todo("should reimburse 50% for damage to items with enchantment >= 8");
    it.todo("should fully reimburse damage to items made of dragon material");
    it.todo("should track remaining cap across multiple claims");
  });
});

