type Item = { type: string; material: string; enchantment: number; cursed: boolean };
type QuoteStep = { op: "quote"; items: Item[] };
type Step = QuoteStep;
type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };

const basePremiumFor = (type: string): number => {
  if (type === "sword") return 100;
  return 60; // amulet
};

export const processScenario = (input: Scenario): { results: { premium: number }[] } => {
  const results = input.steps.map((step) => {
    const base = step.items.reduce((sum, item) => sum + basePremiumFor(item.type), 0);
    const withFirstInsurance = base * 1.10;
    const premium = Math.ceil(withFirstInsurance) + 5;
    return { premium };
  });
  return { results };
};

