type Item = { type: string; material: string; enchantment: number; cursed: boolean; component?: boolean };
type QuoteStep = { op: "quote"; items: Item[] };
type Step = QuoteStep;
type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

const basePremiumFor = (type: string): number => BASE_PREMIUM[type];

export const processScenario = (input: Scenario): { results: { premium: number }[] } => {
  const results = input.steps.map((step) => {
    const base = step.items.reduce(
      (sum, item) => sum + (item.component ? 25 : basePremiumFor(item.type)),
      0,
    );
    const withFirstInsurance = Math.ceil((base * 110) / 100);
    const premium = withFirstInsurance + 5;
    return { premium };
  });
  return { results };
};

